#!/usr/bin/env node
'use strict';

const fs = require('fs');
const path = require('path');

const HOOK_CONTENT = `#!/bin/sh
# GIT PRE-PUSH HOOK: ZERO-DEFECT INTEGRITY GATE
# Automatically generated by setup-integrity-hook.js

echo " Running String Integrity & Invisible Character Gate..."
node scripts/maintenance/string-integrity-gate.js
if [ $? -ne 0 ] ; then
  echo " [GIT] Push rejected: String integrity or invisible character violations found."
  exit 1
fi

echo " Running Zero Defect Architect Audit..."
node scripts/maintenance/zero-defect-architect-audit.js
if [ $? -ne 0 ] ; then
  echo " [GIT] Push rejected: Zero Defect Audit failed."
  exit 1
fi

echo " [GIT] Integrity check passed. Proceeding with push..."
exit 0
`;

const gitHooksDir = path.join(process.cwd(), '.git', 'hooks');
const prePushHook = path.join(gitHooksDir, 'pre-push');

if (!fs.existsSync(gitHooksDir)) {
    console.error(' .git/hooks directory not found. Are you in the root of a git repository? ')      ;
    process.exit(1 );
}

try {
    fs.writeFileSync(prePushHook, HOOK_CONTENT, { mode: 0o755 });
    console.log(' Pre-push hook installed successfully in .git/hooks/pre-push');
} catch (err) {
    console.error(' Failed to install pre-push hook:', err.message);
    process.exit(1);
}
